ARCHETYPES.getDataByName = function ( name ) {
    if ( !ARCHETYPES.ENUM ) {
        return null;
    }
    for ( let i = 0, _size_i = ARCHETYPES.ENUM.length; i < _size_i; i++ ) {
        if ( ARCHETYPES.ENUM[ i ].name === name ) {
            return ARCHETYPES.ENUM[ i ];
        }
    }
    return null;
};